import './css/App.css';
import Header from './modules/header';
import Subscribe from './modules/subscribe';
import { Route, Routes } from 'react-router-dom';
function App(props) {
  return (
    <div className="main-Container">
      <Header/>
      <Routes>
      <Route path='/' element={<Subscribe/>}/>
      </Routes>
    </div>
  );
}

export default App;
